const pergunta = $('Editar Dados').first().json.message_content.toLowerCase();

const modulos = [
  { nome: "Chamamento Público", palavras: ["chamamento", "dispensa", "inexigibilidade", "disponibilizar", "disponibilização", "edital"] },
  { nome: "Cadastro de Ente", palavras: ["ente", "usuário", "usuários", "cadastro de ente", "cnpj", "organização social", "os ", "cadastramento"] },
  { nome: "Proposta", palavras: ["proposta", "encaminhar proposta", "responder exigência", "exigência"] },
  { nome: "Parceria", palavras: ["parceria", "formalizar", "aditar", "aditivo", "termo de colaboração", "termo de fomento"] },
  { nome: "Execução", palavras: ["execução", "empenho", "ingresso de recurso", "pagamento"] },
  { nome: "Prestação de Contas", palavras: ["prestação de contas", "análise de pagamento", "financeira", "finalística", "plano de trabalho", "meta"] },
  { nome: "Consultas Públicas", palavras: ["consulta pública", "consultas públicas"] }
];

let moduloIdentificado = "Não identificado";

for (const modulo of modulos) {
  if (modulo.palavras.some(palavra => pergunta.includes(palavra))) {
    moduloIdentificado = modulo.nome;
    break;
  }
}

return [{
  json: {
    ...$input.item.json,
    modulo: moduloIdentificado
  }
}];
